#include <bits/stdc++.h>
using namespace std;

const int N=3e5+10,mod=998244353;

int n,a[N],f[N],s[N],g[N],sum[41][3];

long long quick_mi(int x,int y){
    long long ans=1,base=x;
    while(y){
        if(y&1)
            ans*=base,ans%=mod;
        base*=base,base%=mod,y>>=1;
    }
    return ans;
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    g[0]=1,s[0]=1,sum[a[1]][0]=0,sum[a[1]][1]=1,sum[a[1]][2]=1;
    for(int i=1;i<=n;i++){
        //printf("%d %d %d\n",sum[a[i]][0],sum[a[i]][1],sum[a[i]][2]);
        s[i]=1LL*s[i-1]*a[i]%mod;
        f[i]=(sum[a[i]][0]+1LL*s[i]*sum[a[i]][1]%mod)%mod;
        g[i]=sum[a[i]][2];
        sum[a[i+1]][0]=(sum[a[i+1]][0]+f[i])%mod;
        sum[a[i+1]][1]=(sum[a[i+1]][1]+1LL*g[i]*quick_mi(s[i],mod-2)%mod)%mod;
        sum[a[i+1]][2]=(sum[a[i+1]][2]+g[i])%mod;
    }
    printf("%d",f[n]);
    return 0;
}
